package scalascript.interpreter.vm.jit

import scalascript.interpreter.Value

/** Runtime helpers for bytecode-JIT HOF method chains.
 *
 *  The bytecode emitters pass compact operation ids instead of materialising
 *  ScalaScript lambda objects in generated bytecode. Unsupported receiver or
 *  value shapes throw; the outer JIT invocation catches and falls back to the
 *  interpreter.
 */
object JitHofDispatch:

  final val OpId     = 0
  final val OpConst  = 1
  final val OpAdd    = 2
  final val OpSub    = 3
  final val OpMul    = 4
  final val OpDiv    = 5
  final val OpMod    = 6
  final val OpSquare = 7
  // Stage 8: specialized String-receiver ops for `s => s.trim.toInt`-like lambdas.
  final val OpStringTrimToInt = 8

  final val PredModEq = 1

  final val FoldAdd = 1

  def rangeUntil(from: Long, until: Long): Object =
    var out: List[Value] = Nil
    var i = until - 1L
    while i >= from do
      out = Value.intV(i) :: out
      i -= 1L
    Value.ListV(out).asInstanceOf[Object]

  def eitherValue(typeName: String, value: Value): Object =
    if typeName != "Right" && typeName != "Left" then
      throw new RuntimeException("JitHofDispatch.eitherValue: unsupported constructor")
    Value.singleValue(typeName, value).asInstanceOf[Object]

  def mapLong(recv: Object, op: Int, c: Long): Object =
    recv match
      case opt: Value.OptionV =>
        if opt.inner == null then Value.NoneV.asInstanceOf[Object]
        else Value.OptionV(Value.intV(applyUnary(opt.inner, op, c))).asInstanceOf[Object]
      case inst: Value.InstanceV if inst.typeName == "Right" =>
        Value.singleValue("Right", Value.intV(applyUnary(valueField(inst), op, c))).asInstanceOf[Object]
      case inst: Value.InstanceV if inst.typeName == "Left" =>
        inst.asInstanceOf[Object]
      case Value.ListV(items) =>
        val buf = scala.collection.mutable.ListBuffer.empty[Value]
        var rem = items
        while rem.nonEmpty do
          buf += Value.intV(applyUnary(rem.head, op, c))
          rem = rem.tail
        Value.ListV(buf.toList).asInstanceOf[Object]
      case _ =>
        throw new RuntimeException("JitHofDispatch.mapLong: unsupported receiver")

  def flatMapGlobalLong(recv: Object, fnName: String): Object =
    recv match
      case opt: Value.OptionV =>
        if opt.inner == null then Value.NoneV.asInstanceOf[Object]
        else normalizeOption(callGlobalValue1(fnName, asLong(opt.inner))).asInstanceOf[Object]
      case inst: Value.InstanceV if inst.typeName == "Right" =>
        callGlobalValue1(fnName, asLong(valueField(inst))).asInstanceOf[Object]
      case inst: Value.InstanceV if inst.typeName == "Left" =>
        inst.asInstanceOf[Object]
      case _ =>
        throw new RuntimeException("JitHofDispatch.flatMapGlobalLong: unsupported receiver")

  /** Fused `recv.map(unary).flatMap(global)` — applies the map to the present
   *  value before invoking the flatMap target, so the intermediate Option/Either
   *  wrapper from `.map` is never allocated. */
  def mapFlatMapGlobalLong(recv: Object, mapOp: Int, mapC: Long, fnName: String): Object =
    recv match
      case opt: Value.OptionV =>
        if opt.inner == null then Value.NoneV.asInstanceOf[Object]
        else normalizeOption(callGlobalValue1(fnName, applyUnary(opt.inner, mapOp, mapC))).asInstanceOf[Object]
      case inst: Value.InstanceV if inst.typeName == "Right" =>
        callGlobalValue1(fnName, applyUnary(valueField(inst), mapOp, mapC)).asInstanceOf[Object]
      case inst: Value.InstanceV if inst.typeName == "Left" =>
        inst.asInstanceOf[Object]
      case _ =>
        throw new RuntimeException("JitHofDispatch.mapFlatMapGlobalLong: unsupported receiver")

  /** Fused `recv.map(unary).getOrElse(default)` — applies the map to the present
   *  value and returns it (or `default` when empty/Left) without allocating the
   *  intermediate Option/Either wrapper from `.map`. */
  def mapGetOrElseLong(recv: Object, mapOp: Int, mapC: Long, default: Long): Long =
    recv match
      case opt: Value.OptionV =>
        if opt.inner == null then default else applyUnary(opt.inner, mapOp, mapC)
      case inst: Value.InstanceV if inst.typeName == "Right" =>
        applyUnary(valueField(inst), mapOp, mapC)
      case inst: Value.InstanceV if inst.typeName == "Left" =>
        default
      case _ =>
        throw new RuntimeException("JitHofDispatch.mapGetOrElseLong: unsupported receiver")

  def filterLong(recv: Object, pred: Int, c1: Long, c2: Long): Object =
    recv match
      case opt: Value.OptionV =>
        if opt.inner == null then Value.NoneV.asInstanceOf[Object]
        else if applyPredicate(opt.inner, pred, c1, c2) then opt.asInstanceOf[Object]
        else Value.NoneV.asInstanceOf[Object]
      case Value.ListV(items) =>
        val buf = scala.collection.mutable.ListBuffer.empty[Value]
        var rem = items
        while rem.nonEmpty do
          val h = rem.head
          if applyPredicate(h, pred, c1, c2) then buf += h
          rem = rem.tail
        Value.ListV(buf.toList).asInstanceOf[Object]
      case _ =>
        throw new RuntimeException("JitHofDispatch.filterLong: unsupported receiver")

  def foldLong(recv: Object, leftConst: Long, rightOp: Int, rightConst: Long): Long =
    recv match
      case opt: Value.OptionV =>
        if opt.inner == null then leftConst else applyUnary(opt.inner, rightOp, rightConst)
      case inst: Value.InstanceV if inst.typeName == "Right" =>
        applyUnary(valueField(inst), rightOp, rightConst)
      case inst: Value.InstanceV if inst.typeName == "Left" =>
        leftConst
      case _ =>
        throw new RuntimeException("JitHofDispatch.foldLong: unsupported receiver")

  def foldLeftLong(recv: Object, init: Long, foldOp: Int): Long =
    recv match
      case Value.ListV(items) =>
        var acc = init
        var rem = items
        while rem.nonEmpty do
          foldOp match
            case FoldAdd => acc += asLong(rem.head)
            case _       => throw new RuntimeException("JitHofDispatch.foldLeftLong: unsupported fold op")
          rem = rem.tail
        acc
      case _ =>
        throw new RuntimeException("JitHofDispatch.foldLeftLong: unsupported receiver")

  /** Fused `map(unary).filter(pred).foldLeft(init)(+)` over a list receiver.
   *  Walks `recv` once with a primitive accumulator — no intermediate ListV,
   *  no per-stage element re-boxing. `map` applies before `filter` (matching
   *  `.map(f).filter(g)` left-to-right semantics). `hasMap`/`hasFilter` gate
   *  the optional stages. Currently only `FoldAdd` is supported. */
  def fusedFoldLong(recv: Object,
                    hasMap: Boolean, mapOp: Int, mapC: Long,
                    hasFilter: Boolean, pred: Int, fc1: Long, fc2: Long,
                    init: Long, foldOp: Int): Long =
    if foldOp != FoldAdd then
      throw new RuntimeException("JitHofDispatch.fusedFoldLong: unsupported fold op")
    recv match
      case Value.ListV(items) =>
        var acc = init
        var rem = items
        while rem.nonEmpty do
          var x = asLong(rem.head)
          if hasMap then x = applyUnaryLong(x, mapOp, mapC)
          if !hasFilter || applyPredicateLong(x, pred, fc1, fc2) then acc += x
          rem = rem.tail
        acc
      case _ =>
        throw new RuntimeException("JitHofDispatch.fusedFoldLong: unsupported receiver")

  /** Range-native variant of [[fusedFoldLong]]: iterates `from until until`
   *  (half-open; the caller passes `hi + 1` for an inclusive `to` range) with
   *  a primitive counter — no `ListV` materialised for the range at all. */
  def fusedRangeFoldLong(from: Long, until: Long,
                         hasMap: Boolean, mapOp: Int, mapC: Long,
                         hasFilter: Boolean, pred: Int, fc1: Long, fc2: Long,
                         init: Long, foldOp: Int): Long =
    if foldOp != FoldAdd then
      throw new RuntimeException("JitHofDispatch.fusedRangeFoldLong: unsupported fold op")
    var acc = init
    var i = from
    while i < until do
      var x = i
      if hasMap then x = applyUnaryLong(x, mapOp, mapC)
      if !hasFilter || applyPredicateLong(x, pred, fc1, fc2) then acc += x
      i += 1L
    acc

  private def applyUnaryLong(x: Long, op: Int, c: Long): Long =
    op match
      case OpId     => x
      case OpConst  => c
      case OpAdd    => x + c
      case OpSub    => x - c
      case OpMul    => x * c
      case OpDiv    => x / c
      case OpMod    => x % c
      case OpSquare => x * x
      case _        => throw new RuntimeException("JitHofDispatch.fusedFoldLong: unsupported unary op")

  private def applyPredicateLong(x: Long, pred: Int, c1: Long, c2: Long): Boolean =
    pred match
      case PredModEq => (x % c1) == c2
      case _         => throw new RuntimeException("JitHofDispatch.fusedFoldLong: unsupported predicate op")

  private def normalizeOption(v: Value): Value.OptionV =
    v match
      case opt: Value.OptionV => opt
      case other              => Value.OptionV(other)

  private def callGlobalValue1(name: String, arg: Long): Value =
    val interp = JitGlobals.getInterp()
    if interp == null then throw new RuntimeException("JitHofDispatch.callGlobalValue1: no interp in TLS")
    interp.globals.getOrElse(name, null) match
      case fn: Value.FunV => interp.invoke(fn, List(Value.intV(arg)))
      case _              => throw new RuntimeException(s"JitHofDispatch.callGlobalValue1: '$name' is not a FunV")

  private def valueField(inst: Value.InstanceV): Value =
    val arr = inst.fieldsArr
    if arr != null && arr.nonEmpty then arr(0)
    else inst.fields.getOrElse("value", Value.UnitV)

  private def asLong(v: Value): Long =
    v match
      case Value.IntV(n)  => n
      case Value.BoolV(b) => if b then 1L else 0L
      case _              => throw new RuntimeException("JitHofDispatch: expected Int/Bool value")

  private def applyUnary(v: Value, op: Int, c: Long): Long =
    // Stage 8: string-receiver ops handled before asLong (which would fail for StringV).
    op match
      case OpStringTrimToInt =>
        v match
          case Value.StringV(s) => s.trim.toInt.toLong
          case _ => throw new ClassCastException(s"OpStringTrimToInt expected StringV, got ${v.getClass.getName}")
      case _ =>
        val x = asLong(v)
        op match
          case OpId     => x
          case OpConst  => c
          case OpAdd    => x + c
          case OpSub    => x - c
          case OpMul    => x * c
          case OpDiv    => x / c
          case OpMod    => x % c
          case OpSquare => x * x
          case _        => throw new RuntimeException("JitHofDispatch: unsupported unary op")

  private def applyPredicate(v: Value, pred: Int, c1: Long, c2: Long): Boolean =
    val x = asLong(v)
    pred match
      case PredModEq => (x % c1) == c2
      case _         => throw new RuntimeException("JitHofDispatch: unsupported predicate op")
